package vo_test

import (
	"bloomo-exam-api/domain/shared/vo"
	"math"
	"testing"
)

func TestNewQuantity(t *testing.T) {
	tests := []struct {
		name           string
		orderAmount    int
		price          int
		expectedValue  float64
		wantErr        bool
		description    string
	}{
		{
			name:          "simple division",
			orderAmount:   4000,
			price:         1000,
			expectedValue: 4.0,
			wantErr:       false,
			description:   "4000 / 1000 = 4.0",
		},
		{
			name:          "truncate to 3 decimal places",
			orderAmount:   6000,
			price:         155,
			expectedValue: 38.709,
			wantErr:       false,
			description:   "6000 / 155 = 38.7096... → 38.709",
		},
		{
			name:          "very small quantity",
			orderAmount:   200,
			price:         1000,
			expectedValue: 0.2,
			wantErr:       false,
			description:   "200 / 1000 = 0.2",
		},
		{
			name:          "truncate to 3 decimal places (complex)",
			orderAmount:   1000,
			price:         333,
			expectedValue: 3.003,
			wantErr:       false,
			description:   "1000 / 333 = 3.003003... → 3.003",
		},
		{
			name:        "invalid zero price",
			orderAmount: 1000,
			price:       0,
			wantErr:     true,
			description: "price must be positive",
		},
		{
			name:        "invalid negative price",
			orderAmount: 1000,
			price:       -100,
			wantErr:     true,
			description: "price must be positive",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got, err := vo.NewQuantity(tt.orderAmount, tt.price)
			if (err != nil) != tt.wantErr {
				t.Errorf("NewQuantity() error = %v, wantErr %v", err, tt.wantErr)
				return
			}
			if !tt.wantErr {
				// 浮動小数点数の比較（誤差を許容）
				if math.Abs(got.Value()-tt.expectedValue) > 1e-9 {
					t.Errorf("NewQuantity() got value %v, want %v (%s)",
						got.Value(), tt.expectedValue, tt.description)
				}
			}
		})
	}
}

func TestQuantity_Value(t *testing.T) {
	t.Run("returns correct value", func(t *testing.T) {
		quantity, _ := vo.NewQuantity(4000, 1000)
		if quantity.Value() != 4.0 {
			t.Errorf("Value() = %v, want 4.0", quantity.Value())
		}
	})
}

package usecase_test

import (
	"bloomo-exam-api/domain/portfolio"
	"bloomo-exam-api/domain/shared/vo"
	"bloomo-exam-api/domain/stock"
	"bloomo-exam-api/domain/trade"
	"bloomo-exam-api/infrastructure/memory"
	"bloomo-exam-api/usecase"
	"testing"
)

// テスト用ヘルパー関数

func mustUserID(id int) vo.UserID {
	uid, err := vo.NewUserID(id)
	if err != nil {
		panic(err)
	}
	return uid
}

func mustTicker(s string) vo.Ticker {
	t, err := vo.NewTicker(s)
	if err != nil {
		panic(err)
	}
	return t
}

func mustPrice(v int) vo.Price {
	p, err := vo.NewPrice(v)
	if err != nil {
		panic(err)
	}
	return p
}

func mustRatio(v int) vo.Ratio {
	r, err := vo.NewRatio(v)
	if err != nil {
		panic(err)
	}
	return r
}

func TestTradeUsecase_Execute(t *testing.T) {
	t.Run("successful trade with valid inputs", func(t *testing.T) {
		// Arrange
		stockRepo := memory.NewStockRepository()
		portfolioRepo := memory.NewPortfolioRepository()

		userID := mustUserID(1)
		calculator := &trade.OrderCalculator{}
		uc := usecase.NewTradeUsecase(stockRepo, portfolioRepo, calculator)

		// Setup repositories
		stockRepo.SaveStock(&stock.Stock{
			Ticker:   mustTicker("A"),
			Price:    mustPrice(1000),
			Tradable: true,
		})
		stockRepo.SaveStock(&stock.Stock{
			Ticker:   mustTicker("B"),
			Price:    mustPrice(155),
			Tradable: true,
		})

		portfolioRepo.SavePortfolio(userID, &portfolio.Portfolio{
			TargetPortfolio: map[vo.Ticker]vo.Ratio{
				mustTicker("A"): mustRatio(40),
				mustTicker("B"): mustRatio(60),
			},
		})

		// Act
		output, err := uc.Execute(usecase.TradeInput{
			UserID: 1,
			Amount: 10000,
		})

		// Assert
		if err != nil {
			t.Fatalf("Execute() error = %v, want nil", err)
		}
		if output == nil {
			t.Fatalf("Execute() output is nil, want non-nil")
		}
		if output.Amount != 10000 {
			t.Errorf("Execute() amount = %d, want 10000", output.Amount)
		}
		if len(output.Orders) != 2 {
			t.Errorf("Execute() orders count = %d, want 2", len(output.Orders))
		}
		if output.TargetPortfolio["A"] != 40 || output.TargetPortfolio["B"] != 60 {
			t.Errorf("Execute() target portfolio mismatch")
		}
	})

	t.Run("error when amount is below minimum", func(t *testing.T) {
		// Arrange
		stockRepo := memory.NewStockRepository()
		portfolioRepo := memory.NewPortfolioRepository()

		calculator := &trade.OrderCalculator{}
		uc := usecase.NewTradeUsecase(stockRepo, portfolioRepo, calculator)

		// Act
		output, err := uc.Execute(usecase.TradeInput{
			UserID: 1,
			Amount: 999,
		})

		// Assert
		if err == nil {
			t.Errorf("Execute() error = nil, want error for invalid amount")
		}
		if output != nil {
			t.Errorf("Execute() output should be nil on error")
		}
	})

	t.Run("error when user_id is invalid", func(t *testing.T) {
		// Arrange
		stockRepo := memory.NewStockRepository()
		portfolioRepo := memory.NewPortfolioRepository()

		calculator := &trade.OrderCalculator{}
		uc := usecase.NewTradeUsecase(stockRepo, portfolioRepo, calculator)

		// Act
		output, err := uc.Execute(usecase.TradeInput{
			UserID: -1,
			Amount: 10000,
		})

		// Assert
		if err == nil {
			t.Errorf("Execute() error = nil, want error for invalid user_id")
		}
		if output != nil {
			t.Errorf("Execute() output should be nil on error")
		}
	})

	t.Run("error when portfolio not found", func(t *testing.T) {
		// Arrange
		stockRepo := memory.NewStockRepository()
		portfolioRepo := memory.NewPortfolioRepository()

		calculator := &trade.OrderCalculator{}
		uc := usecase.NewTradeUsecase(stockRepo, portfolioRepo, calculator)

		stockRepo.SaveStock(&stock.Stock{
			Ticker:   mustTicker("A"),
			Price:    mustPrice(1000),
			Tradable: true,
		})

		// Act
		output, err := uc.Execute(usecase.TradeInput{
			UserID: 999,
			Amount: 10000,
		})

		// Assert
		if err == nil {
			t.Errorf("Execute() error = nil, want error for portfolio not found")
		}
		if output != nil {
			t.Errorf("Execute() output should be nil on error")
		}
	})

	t.Run("successful trade with tradable false filter", func(t *testing.T) {
		// Arrange
		stockRepo := memory.NewStockRepository()
		portfolioRepo := memory.NewPortfolioRepository()

		userID := mustUserID(2)
		calculator := &trade.OrderCalculator{}
		uc := usecase.NewTradeUsecase(stockRepo, portfolioRepo, calculator)

		stockRepo.SaveStock(&stock.Stock{
			Ticker:   mustTicker("A"),
			Price:    mustPrice(1000),
			Tradable: true,
		})
		stockRepo.SaveStock(&stock.Stock{
			Ticker:   mustTicker("B"),
			Price:    mustPrice(155),
			Tradable: false,
		})

		portfolioRepo.SavePortfolio(userID, &portfolio.Portfolio{
			TargetPortfolio: map[vo.Ticker]vo.Ratio{
				mustTicker("A"): mustRatio(40),
				mustTicker("B"): mustRatio(60),
			},
		})

		// Act
		output, err := uc.Execute(usecase.TradeInput{
			UserID: 2,
			Amount: 10000,
		})

		// Assert
		if err != nil {
			t.Fatalf("Execute() error = %v, want nil", err)
		}
		// Bはtradable=falseなので、1注文のみ（A）
		if len(output.Orders) != 1 {
			t.Errorf("Execute() orders count = %d, want 1", len(output.Orders))
		}
		if output.Orders[0].Symbol != "A" {
			t.Errorf("Execute() order symbol = %s, want A", output.Orders[0].Symbol)
		}
	})

	t.Run("empty orders when all stocks are untradable", func(t *testing.T) {
		// Arrange
		stockRepo := memory.NewStockRepository()
		portfolioRepo := memory.NewPortfolioRepository()

		userID := mustUserID(3)
		calculator := &trade.OrderCalculator{}
		uc := usecase.NewTradeUsecase(stockRepo, portfolioRepo, calculator)

		stockRepo.SaveStock(&stock.Stock{
			Ticker:   mustTicker("A"),
			Price:    mustPrice(1000),
			Tradable: false,
		})

		portfolioRepo.SavePortfolio(userID, &portfolio.Portfolio{
			TargetPortfolio: map[vo.Ticker]vo.Ratio{
				mustTicker("A"): mustRatio(100),
			},
		})

		// Act
		output, err := uc.Execute(usecase.TradeInput{
			UserID: 3,
			Amount: 10000,
		})

		// Assert
		if err != nil {
			t.Fatalf("Execute() error = %v, want nil", err)
		}
		if len(output.Orders) != 0 {
			t.Errorf("Execute() orders count = %d, want 0", len(output.Orders))
		}
	})
}

